/* =========================================
   1. CORE LAYOUT & VARIABLES
   ========================================= */
.dashboard-layout {
  display: flex;
  height: 100vh;
  background-color: #0b0f1a; 
  color: #f8fafc;
  overflow: hidden;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Common Gradients & Colors */
.gradient-text {
  background: linear-gradient(to right, #60a5fa, #34d399);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.text-blue { color: #60a5fa; }
.text-green { color: #34d399; }
.text-red { color: #f87171; }

/* Status Dots */
.dot-online { background-color: #34d399; box-shadow: 0 0 8px #34d399; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }
.dot-offline { background-color: #4b5563; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }
.dot-warning { background-color: #f59e0b; box-shadow: 0 0 8px #f59e0b; display: inline-block; width: 8px; height: 8px; border-radius: 50%; }

/* =========================================
   2. SIDEBAR COMPONENTS
   ========================================= */
.sidebar {
  width: 240px;
  min-width: 240px; 
  background-color: #161b2c;
  border-right: 1px solid #232a3d;
  display: flex;
  flex-direction: column;
  position: sticky;
  top: 0;
  height: 100vh;
  z-index: 100;
  transition: left 0.3s ease; /* Smooth transition for mobile */
}

/* --- LOGO AREA FIX --- */
.sidebar-logo {
  padding: 30px 20px;
  display: flex;
  justify-content: space-between; /* Space between logo group and close btn */
  align-items: center;
  border-bottom: 1px solid #232a3d;
  width: 100%;
  box-sizing: border-box;
}

.logo-title {
  display: flex;
  align-items: center;
  gap: 12px;
}

.logo-title h2 {
  font-size: 22px !important;
  margin: 0 !important;
  line-height: 1 !important;
  font-weight: 700;
}

/* Close button hidden by default on desktop */
.close-sidebar-btn {
  display: none; 
}

/* --- NAVIGATION --- */
.sidebar-nav {
  flex: 1;
  padding: 20px 0;
  overflow-y: auto; /* Allow scrolling if many links */
}

.sidebar-nav a {
  display: block;
  padding: 12px 20px;
  color: #707a91;
  text-decoration: none;
  font-size: 0.9rem;
  transition: 0.2s;
  border-left: 4px solid transparent;
}

.sidebar-nav a.active, /* Use .active for React Router NavLink default */
.sidebar-nav a:hover {
  background: #1e2539;
  color: #60a5fa !important;
  border-left: 4px solid #3b82f6;
}

/* --- USER PROFILE (BOTTOM) --- */
.sidebar-bottom {
  padding: 20px;
  border-top: 1px solid #232a3d;
}

.user-profile {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 15px;
}

.user-avatar {
  font-size: 1.5rem;
  background: #0b0f1a;
  padding: 8px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.user-meta {
  display: flex !important;
  flex-direction: column !important;
  align-items: flex-start !important;
  justify-content: center;
  gap: 2px;
}

.user-name {
  font-weight: 600;
  font-size: 0.9rem;
  color: #f8fafc;
}

.user-role-tag {
  font-size: 0.75rem;
  color: #707a91;
}

.logout-btn {
  display: block;
  width: 100%;
  padding: 10px;
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.2);
  border-radius: 8px;
  text-align: center;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s, color 0.2s;
}

.logout-btn:hover {
  background: #ef4444;
  color: white;
}

/* =========================================
   3. MAIN CONTENT DASHBOARD
   ========================================= */
.dashboard-main {
  flex: 1;
  padding: 30px;
  overflow-y: auto;
  overflow-x: hidden;
}

.dashboard-header {
  display: flex;
  justify-content: space-between;
  align-items: center; 
  margin-bottom: 30px;
}

.header-titles h1 { 
  font-size: 1.8rem; 
  margin: 0; 
}

.header-titles p { 
  color: #707a91; 
  font-size: 0.85rem; 
  margin: 5px 0 0 0; 
}

.header-time { 
  text-align: right; 
}

.time-text { 
  font-weight: 600; 
  margin: 0 0 5px 0; 
  color: #e2e8f0; 
  font-size: 0.95rem;
}

.timezone-text { 
  font-size: 0.8rem; 
  color: #707a91; 
  margin: 0; 
}

/* --- GRID SYSTEM (3-Column Top) --- */
.top-summary-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
  margin-bottom: 30px;
}

.summary-card {
  background: #1e2539;
  padding: 20px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  gap: 15px;
  border: 1px solid #2d364f;
}

.icon-wrapper {
  width: 45px;
  height: 45px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
}

.blue-icon { background: rgba(59, 130, 246, 0.15); color: #60a5fa; }
.purple-icon { background: rgba(168, 85, 247, 0.15); color: #c084fc; }
.red-icon { background: rgba(239, 68, 68, 0.15); color: #f87171; }

.summary-info h2 { margin: 0; font-size: 1.6rem; color: #f8fafc; }
.summary-info p { margin: 0; color: #707a91; font-size: 0.8rem; }

/* --- RECENT ACTIVITY (4-Column Middle) --- */
.activity-cards-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
  margin-bottom: 30px;
}

.activity-card {
  background: #1e2539;
  padding: 25px;
  border-radius: 12px;
  text-align: center;
  border: 1px solid #2d364f;
}

.act-icon { font-size: 1.5rem; }
.activity-card h2 { font-size: 2rem; margin: 10px 0; }
.activity-card p { font-size: 0.8rem; color: #707a91; margin: 0; }

/* --- CHARTS (2-Column Bottom) --- */
.charts-section {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

.chart-card {
  background: #1e2539;
  padding: 20px;
  border-radius: 12px;
  border: 1px solid #2d364f;
}

.chart-card h3 {
  font-size: 1rem;
  color: #e2e8f0;
  margin-top: 0;
  margin-bottom: 15px;
}

.mock-bar-chart {
  display: flex;
  justify-content: space-around;
  align-items: flex-end;
  height: 200px;
  margin-top: 20px;
  border-bottom: 1px solid #2d364f;
  padding-bottom: 25px;
}

.bar-wrapper {
  width: 30px;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  position: relative;
}

.bar {
  width: 100%;
  background: linear-gradient(to top, #3b82f6, #93c5fd);
  border-radius: 4px 4px 0 0;
}

.bar-wrapper span {
  position: absolute;
  bottom: -25px;
  width: 100%;
  text-align: center;
  font-size: 0.7rem;
  color: #707a91;
}

.mock-line-chart {
  height: 200px;
  background: #0b0f1a;
  border: 1px dashed #2d364f;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-top: 20px;
  color: #4b5563;
  font-size: 0.8rem;
}

/* =========================================
   4. CAMERAS PAGE SPECIFICS
   ========================================= */
.camera-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 25px;
}

.camera-card {
  background: #1e2539;
  border-radius: 12px;
  border: 1px solid #2d364f;
  overflow: hidden;
  transition: transform 0.2s, border-color 0.2s;
}

.camera-card:hover {
  transform: translateY(-3px);
  border-color: #3b82f6;
}

.camera-alert {
  border: 1px solid #ef4444;
  box-shadow: 0 0 15px rgba(239, 68, 68, 0.2);
}

.camera-feed-placeholder {
  height: 180px;
  background: #0b0f1a;
  display: flex;
  align-items: center;
  justify-content: center;
  border-bottom: 1px solid #2d364f;
  position: relative;
}

.feed-live-icon {
  position: absolute;
  top: 15px;
  right: 15px;
  color: #ef4444;
  font-size: 0.8rem;
  font-weight: bold;
  animation: blink 2s infinite;
}

@keyframes blink {
  0% { opacity: 1; }
  50% { opacity: 0; }
  100% { opacity: 1; }
}

.feed-offline-text {
  color: #4b5563;
  font-weight: bold;
  letter-spacing: 2px;
}

.camera-info {
  padding: 20px;
}

.cam-title-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 5px;
}

.cam-title-row h3 { margin: 0; font-size: 1.1rem; color: #f8fafc; }
.camera-info p { margin: 0; font-size: 0.85rem; color: #707a91; }

/* =========================================
   5. V-PATROL PAGE SPECIFICS
   ========================================= */
.vpatrol-container {
  background: #1e2539;
  border-radius: 12px;
  border: 1px solid #2d364f;
  padding: 10px;
}

.incident-row {
  display: flex;
  align-items: center;
  padding: 20px;
  border-bottom: 1px solid #2d364f;
  gap: 30px;
}

.incident-row:last-child {
  border-bottom: none;
}

.severity-critical { border-left: 4px solid #ef4444; }
.severity-high { border-left: 4px solid #f59e0b; }
.severity-medium { border-left: 4px solid #3b82f6; }
.severity-safe { border-left: 4px solid #34d399; }

.incident-time {
  display: flex;
  flex-direction: column;
  min-width: 100px;
}

.incident-time strong { color: #f8fafc; font-size: 0.95rem; }
.incident-time span { color: #707a91; font-size: 0.75rem; margin-top: 4px; }

.incident-details {
  flex: 1;
}

.incident-details h3 { margin: 0 0 5px 0; font-size: 1.05rem; color: #f8fafc; }
.incident-details p { margin: 0; font-size: 0.9rem; color: #94a3b8; }

.review-btn {
  background: transparent;
  border: 1px solid #3b82f6;
  color: #60a5fa;
  padding: 8px 16px;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
  transition: background 0.2s, color 0.2s;
}

.review-btn:hover {
  background: #3b82f6;
  color: white;
}

/* =========================================
   6. RESPONSIVE DESIGN (TABLET & MOBILE)
   ========================================= */
.mobile-menu-btn {
  display: none !important; 
  position: absolute;
}

@media (max-width: 1024px) {
  .top-summary-row { grid-template-columns: repeat(2, 1fr); }
  .activity-cards-grid { grid-template-columns: repeat(2, 1fr); }
  .charts-section { grid-template-columns: 1fr; }
}

@media (max-width: 768px) {
  /* Hamburger Button */
  .mobile-menu-btn {
    display: flex !important;
    position: fixed;
    top: 15px;
    left: 15px;
    z-index: 1000;
    width: 45px;
    height: 45px;
    background: rgba(30, 41, 59, 0.8);
    color: white;
    border: 1px solid #334155;
    border-radius: 8px;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    cursor: pointer;
    backdrop-filter: blur(5px);
  }

  /* Sidebar Canvas Behavior */
  .sidebar {
    position: fixed;
    left: -100%;
    z-index: 999;
  }

  .sidebar.open {
    left: 0;
  }

  /* Activate Close Button inside Sidebar */
  .close-sidebar-btn {
    display: flex; 
    background: transparent;
    color: #94a3b8;
    border: none;
    font-size: 1.5rem;
    cursor: pointer;
    padding: 5px;
    align-items: center;
    justify-content: center;
    transition: color 0.3s ease;
  }

  .close-sidebar-btn:hover,
  .close-sidebar-btn:active {
    color: #f8fafc;
  }

  /* Overlay Background */
  .sidebar-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: rgba(0, 0, 0, 0.6);
    backdrop-filter: blur(2px);
    z-index: 998; 
  }

  /* Main Content Adjustments */
  .dashboard-main {
    padding: 90px 20px 20px;
  }

  .dashboard-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 15px;
  }

  .header-time {
    text-align: left;
  }

  .top-summary-row, 
  .activity-cards-grid {
    grid-template-columns: 1fr;
  }
}

