/* =========================================
   OBJECT DETECTION PAGE LAYOUT
   ========================================= */
.od-grid {
    display: grid;
    grid-template-columns: 1.4fr 1fr;
    grid-template-rows: auto auto;
    gap: 16px;
}

/* =========================================
   STREAM PANEL
   ========================================= */
.od-stream-card {
    background: #1e2539;
    border-radius: 16px;
    border: 1px solid #2d364f;
    padding: 16px;
    grid-row: 1 / 2;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.od-stream-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.od-stream-header h2 {
    margin: 0;
    font-size: 1rem;
    color: #f8fafc;
    font-weight: 600;
}

.od-people-badge {
    display: flex;
    align-items: center;
    gap: 8px;
    background: rgba(6, 182, 212, 0.12);
    border: 1px solid rgba(6, 182, 212, 0.35);
    border-radius: 8px;
    padding: 6px 14px;
    font-family: 'Courier New', monospace;
    font-size: 0.85rem;
    color: #22d3ee;
    font-weight: 700;
}

.od-people-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #22d3ee;
    box-shadow: 0 0 6px #22d3ee;
    animation: odPulse 1.2s ease-in-out infinite;
}

.od-stream-img {
    width: 100%;
    border-radius: 10px;
    background: #0b0f1a;
    border: 1px solid #2d364f;
    display: block;
}

.od-stream-placeholder {
    width: 100%;
    aspect-ratio: 4 / 3;
    background: #0b0f1a;
    border-radius: 10px;
    border: 1px dashed #2d364f;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #4b5563;
    font-size: 0.85rem;
    font-family: monospace;
}

/* =========================================
   RIGHT COLUMN — Zones + Alerts stacked
   ========================================= */
.od-right-column {
    grid-column: 2 / 3;
    grid-row: 1 / 3;
    display: flex;
    flex-direction: column;
    gap: 16px;
    min-height: 0;
}

/* =========================================
   ZONES CARD
   ========================================= */
.od-card {
    background: #1e2539;
    border-radius: 16px;
    border: 1px solid #2d364f;
    padding: 20px;
    display: flex;
    flex-direction: column;
    gap: 14px;
